{
    "level": "B1",
    "intro": "In this topic you will learn the common English sequence <strong>opinion, size, age, shape, color, origin, material, purpose</strong>.",
    "rules": [
        {
            "label": "TYPICAL ORDER",
            "color": "emerald",
            "text": "The usual pattern is <strong>opinion → size → age → shape → color → origin → material → purpose</strong>.",
            "example": "a lovely small old round brown Italian wooden table"
        },
        {
            "label": "NOT ALL SLOTS",
            "color": "blue",
            "text": "You do not have to fill every slot. Most sentences use only one to three adjectives.",
            "example": "a nice blue shirt"
        },
        {
            "label": "CLOSE TO NOUN",
            "color": "amber",
            "text": "<strong>Material</strong> and <strong>purpose</strong> often stand closest to the noun.",
            "example": "a black leather jacket / a sleeping bag"
        }
    ]
}

{
    "title": "1. Typical order",
    "intro": "Remember the most common sequence.",
    "items": [
        {
            "label": "1",
            "title": "opinion",
            "subtitle": "nice, ugly, beautiful"
        },
        {
            "label": "2",
            "title": "size",
            "subtitle": "big, small, tall"
        },
        {
            "label": "3",
            "title": "age / shape",
            "subtitle": "old, young, round, square"
        },
        {
            "label": "4",
            "title": "color / origin",
            "subtitle": "red, blue, Italian, Ukrainian"
        },
        {
            "label": "5",
            "title": "material / purpose",
            "subtitle": "wooden, metal, sleeping, racing"
        },
        {
            "label": "6",
            "title": "noun",
            "subtitle": "bag, table, shoes, car"
        }
    ]
}

{
    "title": "2. How it sounds natural",
    "sections": [
        {
            "label": "Short natural phrases",
            "color": "emerald",
            "description": "In real speech, two or three adjectives are often enough.",
            "examples": [
                {
                    "en": "a beautiful old house",
                    "ua": "a beautiful old house"
                },
                {
                    "en": "a small black dog",
                    "ua": "a small black dog"
                },
                {
                    "en": "an expensive Italian car",
                    "ua": "an expensive Italian car"
                }
            ]
        },
        {
            "label": "Longer strings",
            "color": "blue",
            "description": "When you use more adjectives, the order becomes more important.",
            "examples": [
                {
                    "en": "a lovely small old round table",
                    "ua": "a lovely small old round table"
                },
                {
                    "en": "a big modern glass office building",
                    "ua": "a big modern glass office building"
                },
                {
                    "en": "a stylish long black wool coat",
                    "ua": "a stylish long black wool coat"
                }
            ]
        },
        {
            "label": "Material and purpose near the noun",
            "color": "amber",
            "description": "Words such as <strong>wooden, plastic, sleeping, racing</strong> usually stay close to the noun.",
            "examples": [
                {
                    "en": "a large brown wooden box",
                    "ua": "a large brown wooden box"
                },
                {
                    "en": "a light blue sleeping bag",
                    "ua": "a light blue sleeping bag"
                },
                {
                    "en": "a fast red racing bike",
                    "ua": "a fast red racing bike"
                }
            ],
            "note": "Purpose adjectives often behave almost like part of the noun."
        }
    ]
}

{
    "title": "3. Common mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Unnatural order.",
            "wrong": "a wooden old box",
            "right": "✅ <span class=\"font-mono\">an old wooden box</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Color before size without a reason.",
            "wrong": "a black small dog",
            "right": "✅ <span class=\"font-mono\">a small black dog</span>"
        },
        {
            "label": "Mistake 3",
            "color": "sky",
            "title": "Purpose too far from the noun.",
            "wrong": "a sleeping blue warm bag",
            "right": "✅ <span class=\"font-mono\">a warm blue sleeping bag</span>"
        }
    ]
}

{
    "title": "4. Quick summary",
    "items": [
        "Typical pattern: <strong>opinion → size → age → shape → color → origin → material → purpose → noun</strong>.",
        "In real speech, one to three adjectives are often enough.",
        "Color usually comes after size / age / shape.",
        "Material and purpose often stand closest to the noun.",
        "If you are unsure, use fewer adjectives but keep a natural order."
    ]
}

